#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e5+10,M=110,Mod=1e4+7,INF=0x3f3f3f3f;int n,m;
inline int qpow(int a,int b){int res=1;while(b){if(b&1)res=1ll*res*a%Mod;a=1ll*a*a%Mod;b=b>>1;}return res;}
struct ACM
{
	int ch[N][28],que[N],nxt[N],H,T,cnt,tot[N];bool flag;int jud[N];int dp[105][N];
	inline void Init(){memset(ch,0,sizeof(ch));memset(tot,0,sizeof(tot));cnt=flag=0;}
	inline void ins(char *s,int q)
	{
		if(flag){puts("Error");exit(0);}int p=0,len=strlen(s);
		rep(0,len-1,i){int &x=ch[p][s[i]-'A'];p=(x?x:x=++cnt);}jud[p]=1;
	}
	inline void build()
	{
		flag=1;H=1;T=0;rep(0,25,i)if(ch[0][i])que[++T]=ch[0][i];
		while(H<=T){int u=que[H++];rep(0,25,i)ch[u][i]?(nxt[que[++T]=ch[u][i]]=ch[nxt[u]][i],jud[ch[u][i]]|=jud[nxt[ch[u][i]]]):ch[u][i]=ch[nxt[u]][i];}
	}
	inline int DP()
	{
		dp[0][0]=1;//rep(0,m-1,i)rep(0,cnt,j)rep(0,25,k)if(!jud[ch[j][k]])dp[ch[j][k]][i+1]+=dp[j][i];
		rep(0,m-1,i)rep(0,cnt,j)rep(0,25,k)if(!jud[ch[j][k]])dp[i+1][ch[j][k]]=(dp[i+1][ch[j][k]]+dp[i][j])%Mod;
//		rep(0,m-1,i)rep(0,cnt,j)rep(0,25,k)printf("%d\n",dp[i+1][ch[j][k]]);
//		rep(0,cnt,i)printf("%d ",jud[i]);puts("");
		int res=0;rep(0,cnt,i)res=(res+dp[m][i])%Mod;return res;
	}
}a;
char ch[M];
int main()
{
	n=read(),m=read();rep(1,n,i)scanf("%s",ch),a.ins(ch,i);
	int ans=qpow(26,m);a.build();printf("%d\n",(ans-a.DP()+Mod)%Mod);return 0;
}
